#include <stdio.h>
#include <math.h>

double calculatePower(double base, long long exponent) {
    if (exponent == 0) return 1.0;
    long long e = exponent;
    if (e < 0) {
        base = 1.0 / base;
        e = -e;
    }
    double result = 1.0;
    while (e > 0) {
        if (e & 1LL) result *= base;
        base *= base;
        e >>= 1LL;
    }
    return result;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double base;
        long long exponent;
        scanf("%lf %lld", &base, &exponent);
        printf("%.5f\n", calculatePower(base, exponent));
    }
    return 0;
}

