code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static double calculatePower(double base, long exponent) {
        if (exponent == 0) return 1.0;
        long e = exponent;
        if (e < 0) {
            base = 1.0 / base;
            e = -e;
        }
        double result = 1.0;
        while (e > 0) {
            if ((e & 1L) == 1L) result *= base;
            base *= base;
            e >>= 1L;
        }
        return result;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            st = new StringTokenizer(br.readLine());
            double base = Double.parseDouble(st.nextToken());
            long exponent = Long.parseLong(st.nextToken());
            double ans = calculatePower(base, exponent);
            sb.append(String.format(java.util.Locale.US, "%.5f", ans)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

