import sys

def calculatePower(base: float, exponent: int) -> float:
    if exponent == 0:
        return 1.0
    e = exponent
    if e < 0:
        base = 1.0 / base
        e = -e
    result = 1.0
    while e:
        if e & 1:
            result *= base
        base *= base
        e >>= 1
    return result

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        base = float(data[idx]); idx += 1
        exponent = int(data[idx]); idx += 1
        out.append(f"{calculatePower(base, exponent):.5f}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

